 51→func TestMimeFromFilename(t *testing.T) {
 52→	tests := []struct {
 53→		name     string
 54→		filename string
 55→		want     string
 56→	}{
 57→		{"mp3", "audio.mp3", "audio/mpeg"},
 58→		{"wav", "recording.wav", "audio/wav"},
 59→		{"ogg", "file.ogg", "audio/ogg"},
 60→		{"webm", "capture.webm", "audio/webm"},
 61→		{"m4a", "voice.m4a", "audio/mp4"},
 62→		{"flac", "lossless.flac", "audio/flac"},
 63→		{"unknown", "file.txt", ""},
 64→		{"no extension", "noext", ""},
 65→		{"uppercase", "FILE.MP3", "audio/mpeg"},
 66→	}
 67→
 68→	for _, tt := range tests {
