357→// TestUploadHandler_FileTooSmall verifies the handler rejects files smaller
358→// than the minimum required for content sniffing.
359→func TestUploadHandler_FileTooSmall(t *testing.T) {
360→	var buf bytes.Buffer
361→	w := multipart.NewWriter(&buf)
362→
363→	partHeader := make(map[string][]string)
364→	partHeader["Content-Disposition"] = []string{`form-data; name="file"; filename="tiny.mp3"`}
365→	partHeader["Content-Type"] = []string{"audio/mpeg"}
366→	part, err := w.CreatePart(partHeader)
367→	if err != nil {
368→		t.Fatal(err)
369→	}
370→
371→	// Write only 4 bytes — too small for reliable sniffing
372→	if _, err := part.Write([]byte{0xFF, 0xFB, 0x90, 0x00}); err != nil {
373→		t.Fatal(err)
374→	}
375→	_ = w.Close()
376→
377→	handler := uploadHandler(&emptyStorage, 50<<20)
378→
379→	req := httptest.NewRequest(http.MethodPost, "/upload", &buf)
380→	req.Header.Set("Content-Type", w.FormDataContentType())
381→	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
382→	req = req.WithContext(ctx)
383→
384→	rr := httptest.NewRecorder()
385→	handler.ServeHTTP(rr, req)
386→
387→	if rr.Code != http.StatusBadRequest {
388→		t.Errorf("expected 400 for tiny file, got %d: %s", rr.Code, rr.Body.String())
389→	}
390→}
