 63→func TestLogging(t *testing.T) {
 64→	inner := http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
 65→		w.WriteHeader(http.StatusCreated)
 66→		_, _ = fmt.Fprint(w, "hello")
 67→	})
 68→
 69→	handler := Logging(inner)
 70→	rr := httptest.NewRecorder()
 71→	handler.ServeHTTP(rr, httptest.NewRequest("GET", "/test", nil))
 72→
 73→	if rr.Code != http.StatusCreated {
 74→		t.Errorf("status = %d, want %d", rr.Code, http.StatusCreated)
 75→	}
 76→	if rr.Body.String() != "hello" {
 77→		t.Errorf("body = %q, want %q", rr.Body.String(), "hello")
 78→	}
