 25→const testHTML = `<!DOCTYPE html>
 26→<html><head><title>Test Page</title></head>
 27→<body>
 28→<article>
 29→<h1>Test Page</h1>
 30→<p>This is a test article with enough content to be extracted by readability.
 31→It needs multiple paragraphs to work properly.</p>
 32→<p>Here is another paragraph with more content to ensure the readability
 33→parser has enough text to extract meaningful content from the page.</p>
 34→<p>And a third paragraph for good measure, because readability needs a
 35→certain amount of content before it considers something an article.</p>
 36→</article>
 37→</body></html>`
