 39→func TestPageFetchWorker_Success(t *testing.T) {
 40→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
 41→		w.Header().Set("Content-Type", "text/html")
 42→		_, _ = w.Write([]byte(testHTML))
 43→	}))
 44→	defer srv.Close()
 45→
 46→	items := &mockItemService{}
