174→func containsStr(s, substr string) bool {
175→	return len(s) >= len(substr) && containsSubstring(s, substr)
176→}
177→
178→func containsSubstring(s, sub string) bool {
179→	for i := 0; i <= len(s)-len(sub); i++ {
180→		if s[i:i+len(sub)] == sub {
181→			return true
182→		}
183→	}
184→	return false
185→}
