173→				return b
174→			}(),
175→			want: "audio/wav",
176→		},
177→		{
178→			name: "OGG",
179→			buf:  append([]byte("OggS"), make([]byte, 20)...),
180→			want: "audio/ogg",
181→		},
182→		{
