package worker

import (
	"context"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/google/uuid"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/item"
)

// mockItemService implements ItemContentUpdater for testing.
type mockItemService struct {
	updates []item.ContentUpdate
}

func (m *mockItemService) UpdateContent(_ context.Context, _ uuid.UUID, input item.ContentUpdate) error {
	m.updates = append(m.updates, input)
	return nil
}

const testHTML = `<!DOCTYPE html>
<html><head><title>Test Page</title></head>
<body>
<article>
<h1>Test Page</h1>
<p>This is a test article with enough content to be extracted by readability.
It needs multiple paragraphs to work properly.</p>
<p>Here is another paragraph with more content to ensure the readability
parser has enough text to extract meaningful content from the page.</p>
<p>And a third paragraph for good measure, because readability needs a
certain amount of content before it considers something an article.</p>
</article>
</body></html>`

func TestPageFetchWorker_Success(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "text/html")
		_, _ = w.Write([]byte(testHTML))
	}))
	defer srv.Close()

	items := &mockItemService{}
	w := &PageFetchWorker{
		Items:  items,
		Client: srv.Client(),
	}

	job := &river.Job[PageFetchArgs]{
		Args: PageFetchArgs{
			ItemID: uuid.New(),
			URL:    srv.URL,
		},
	}

	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("Work() returned error: %v", err)
	}

	// Should have called UpdateContent twice: processing + ready
	if len(items.updates) != 2 {
		t.Fatalf("expected 2 UpdateContent calls, got %d", len(items.updates))
	}

	if items.updates[0].Status != "processing" {
		t.Errorf("first update status = %q, want %q", items.updates[0].Status, "processing")
	}

	final := items.updates[1]
	if final.Status != "ready" {
		t.Errorf("final status = %q, want %q", final.Status, "ready")
	}
	if final.Title == nil || *final.Title == "" {
		t.Error("expected non-empty title in final update")
	}
	if final.ContentText == nil || *final.ContentText == "" {
		t.Error("expected non-empty content_text in final update")
	}
}

func TestPageFetchWorker_HTTPError(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusNotFound)
	}))
	defer srv.Close()

	items := &mockItemService{}
	w := &PageFetchWorker{
		Items:  items,
		Client: srv.Client(),
	}

	job := &river.Job[PageFetchArgs]{
		Args: PageFetchArgs{
			ItemID: uuid.New(),
			URL:    srv.URL,
		},
	}

	err := w.Work(context.Background(), job)
	if err == nil {
		t.Fatal("Work() should return error for 404")
	}

	// Should have set processing then error
	if len(items.updates) != 2 {
		t.Fatalf("expected 2 UpdateContent calls, got %d", len(items.updates))
	}
	if items.updates[1].Status != "error" {
		t.Errorf("error update status = %q, want %q", items.updates[1].Status, "error")
	}
}

func TestPageFetchWorker_ConnectionError(t *testing.T) {
	items := &mockItemService{}
	w := &PageFetchWorker{
		Items:  items,
		Client: &http.Client{},
	}

	job := &river.Job[PageFetchArgs]{
		Args: PageFetchArgs{
			ItemID: uuid.New(),
			URL:    "http://localhost:1", // nothing listening
		},
	}

	err := w.Work(context.Background(), job)
	if err == nil {
		t.Fatal("Work() should return error for connection failure")
	}

	if len(items.updates) < 2 {
		t.Fatalf("expected at least 2 UpdateContent calls, got %d", len(items.updates))
	}
	if items.updates[1].Status != "error" {
		t.Errorf("error update status = %q, want %q", items.updates[1].Status, "error")
	}
}

func TestPageFetchWorker_NilStorage(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "text/html")
		_, _ = w.Write([]byte(testHTML))
	}))
	defer srv.Close()

	items := &mockItemService{}
	w := &PageFetchWorker{
		Items:   items,
		Storage: nil,
		Client:  srv.Client(),
	}

	job := &river.Job[PageFetchArgs]{
		Args: PageFetchArgs{
			ItemID: uuid.New(),
			URL:    srv.URL,
		},
	}

	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("Work() returned error: %v", err)
	}

	final := items.updates[len(items.updates)-1]
	if final.ContentURL != nil {
		t.Error("expected nil ContentURL when storage is not configured")
	}
}

func TestPageFetchWorker_UserAgent(t *testing.T) {
	var gotUA string
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		gotUA = r.Header.Get("User-Agent")
		w.Header().Set("Content-Type", "text/html")
		_, _ = w.Write([]byte(testHTML))
	}))
	defer srv.Close()

	items := &mockItemService{}
	w := &PageFetchWorker{
		Items:  items,
		Client: srv.Client(),
	}

	job := &river.Job[PageFetchArgs]{
		Args: PageFetchArgs{
			ItemID: uuid.New(),
			URL:    srv.URL,
		},
	}

	_ = w.Work(context.Background(), job)

	if gotUA != userAgent {
		t.Errorf("User-Agent = %q, want %q", gotUA, userAgent)
	}
}

package worker

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"path/filepath"
	"strings"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/storage"
)

// TranscribeArgs are the arguments for a transcription job.
type TranscribeArgs struct {
	ItemID   uuid.UUID `json:"item_id"`
	OwnerID  uuid.UUID `json:"owner_id"`
	AudioKey string    `json:"audio_key"`
}

func (TranscribeArgs) Kind() string { return "transcribe" }

// TranscribeWorker transcribes audio via Whisper API or local whisper.cpp.
type TranscribeWorker struct {
	river.WorkerDefaults[TranscribeArgs]
	Storage     *storage.Client
	Transcriber provider.Transcriber
	Pool        *pgxpool.Pool
	RiverClient *river.Client[pgx.Tx] // for enqueuing follow-up jobs (embed)
}

func (w *TranscribeWorker) Work(ctx context.Context, job *river.Job[TranscribeArgs]) error {
	slog.InfoContext(ctx, "worker: transcribe: processing",
		"item_id", job.Args.ItemID,
		"audio_key", job.Args.AudioKey,
	)

	if w.Storage == nil {
		return fmt.Errorf("worker: transcribe: storage not configured")
	}
	if w.Transcriber == nil {
		return fmt.Errorf("worker: transcribe: transcriber not configured")
	}

	// Update item status to processing
	if err := w.updateStatus(ctx, job.Args.ItemID, job.Args.OwnerID, "processing", nil); err != nil {
		return fmt.Errorf("worker: transcribe: set processing: %w", err)
	}

	// Download audio from S3
	reader, err := w.Storage.Download(ctx, job.Args.AudioKey)
	if err != nil {
		w.setError(ctx, job.Args.ItemID, job.Args.OwnerID, "failed to download audio")
		return fmt.Errorf("worker: transcribe: download audio: %w", err)
	}
	defer func() { _ = reader.Close() }()

	// Determine format from key extension
	ext := strings.TrimPrefix(filepath.Ext(job.Args.AudioKey), ".")
	if ext == "" {
		ext = "wav"
	}

	// Transcribe
	transcript, err := w.Transcriber.Transcribe(ctx, reader, provider.TranscribeOpts{
		Format: ext,
	})
	if err != nil {
		w.setError(ctx, job.Args.ItemID, job.Args.OwnerID, "transcription failed")
		return fmt.Errorf("worker: transcribe: transcribe: %w", err)
	}

	// Update item with transcript
	_, err = w.Pool.Exec(ctx,
		`UPDATE items SET content_text = $1, status = 'ready', updated_at = now()
		 WHERE id = $2 AND owner_id = $3`,
		transcript, job.Args.ItemID, job.Args.OwnerID)
	if err != nil {
		return fmt.Errorf("worker: transcribe: update item: %w", err)
	}

	slog.InfoContext(ctx, "worker: transcribe: completed",
		"item_id", job.Args.ItemID,
		"transcript_len", len(transcript),
	)

	// Enqueue embedding job for the transcript
	if transcript != "" {
		w.enqueueEmbed(ctx, job.Args.ItemID, transcript)
	}

	return nil
}

func (w *TranscribeWorker) enqueueEmbed(ctx context.Context, itemID uuid.UUID, content string) {
	if w.RiverClient == nil {
		return
	}
	_, err := w.RiverClient.Insert(ctx, &EmbedArgs{
		ItemID:  itemID,
		Content: content,
	}, nil)
	if err != nil {
		slog.ErrorContext(ctx, "worker: transcribe: failed to enqueue embed job",
			"item_id", itemID,
			"error", err,
		)
	}
}

// updateStatus sets the item's status and optionally stores an error in metadata.
func (w *TranscribeWorker) updateStatus(ctx context.Context, itemID, ownerID uuid.UUID, status string, errMsg *string) error {
	if errMsg != nil {
		meta := map[string]any{"error": *errMsg}
		metaJSON, err := json.Marshal(meta)
		if err != nil {
			return fmt.Errorf("worker: transcribe: marshal error metadata: %w", err)
		}
		_, err = w.Pool.Exec(ctx,
			`UPDATE items SET status = $1, metadata = metadata || $4::jsonb, updated_at = now()
			 WHERE id = $2 AND owner_id = $3`,
			status, itemID, ownerID, metaJSON)
		return err
	}
	_, err := w.Pool.Exec(ctx,
		`UPDATE items SET status = $1, updated_at = now() WHERE id = $2 AND owner_id = $3`,
		status, itemID, ownerID)
	return err
}

// setError is a convenience method that sets the item status to "error".
func (w *TranscribeWorker) setError(ctx context.Context, itemID, ownerID uuid.UUID, msg string) {
	if err := w.updateStatus(ctx, itemID, ownerID, "error", &msg); err != nil {
		slog.ErrorContext(ctx, "worker: transcribe: failed to set error status",
			"item_id", itemID,
			"error", err,
		)
	}
}

