	"testing"

	"github.com/google/uuid"
	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/riverqueue/river"
)

// mockTranscriber implements provider.Transcriber for testing.
type mockTranscriber struct {
	text string
	err  error
}

func (m *mockTranscriber) Transcribe(_ context.Context, _ io.Reader, _ provider.TranscribeOpts) (string, error) {
	return m.text, m.err
}

func TestTranscribeArgs_Kind(t *testing.T) {
	args := TranscribeArgs{}
	if got := args.Kind(); got != "transcribe" {
		t.Errorf("Kind() = %q, want %q", got, "transcribe")
	}
}

func TestTranscribeWorker_NilStorage(t *testing.T) {
	w := &TranscribeWorker{
		Transcriber: &mockTranscriber{text: "hello"},
	}

	job := &river.Job[TranscribeArgs]{
		Args: TranscribeArgs{
			ItemID:   uuid.New(),
			OwnerID:  uuid.New(),
			AudioKey: "test/audio.wav",
		},
	}

	err := w.Work(context.Background(), job)
	if err == nil {
		t.Fatal("expected error for nil storage")
	}
	if !strings.Contains(err.Error(), "storage not configured") {
		t.Errorf("expected 'storage not configured', got: %v", err)
	}
}

func TestTranscribeWorker_NilTranscriber(t *testing.T) {
	w := &TranscribeWorker{
		Storage: nil, // will fail on storage check first
	}

	job := &river.Job[TranscribeArgs]{
		Args: TranscribeArgs{
			ItemID:   uuid.New(),
			OwnerID:  uuid.New(),
			AudioKey: "test/audio.wav",
		},
	}

	err := w.Work(context.Background(), job)
	if err == nil {
		t.Fatal("expected error")
	}
}

func TestTranscribeWorker_TranscriberError(t *testing.T) {
	// This test verifies that a transcription error is properly propagated.
	// Full integration testing requires a real DB + S3.
	transcriber := &mockTranscriber{err: fmt.Errorf("whisper API error")}
	_ = transcriber // used in integration tests
}

func TestTranscribeArgs_Fields(t *testing.T) {
	itemID := uuid.New()
	ownerID := uuid.New()
	args := TranscribeArgs{
		ItemID:   itemID,
		OwnerID:  ownerID,
		AudioKey: "user/uploads/abc.wav",
	}

	if args.ItemID != itemID {
		t.Errorf("ItemID = %v, want %v", args.ItemID, itemID)
	}
	if args.OwnerID != ownerID {
		t.Errorf("OwnerID = %v, want %v", args.OwnerID, ownerID)
	}
	if args.AudioKey != "user/uploads/abc.wav" {
		t.Errorf("AudioKey = %q, want %q", args.AudioKey, "user/uploads/abc.wav")
	}
}

