	return nil
}

const testHTML = `<!DOCTYPE html>
<html><head><title>Test Page</title></head>
<body>
<article>
<h1>Test Page</h1>
<p>This is a test article with enough content to be extracted by readability.
It needs multiple paragraphs to work properly.</p>
<p>Here is another paragraph with more content to ensure the readability
parser has enough text to extract meaningful content from the page.</p>
<p>And a third paragraph for good measure, because readability needs a
certain amount of content before it considers something an article.</p>
</article>
</body></html>`

func TestPageFetchWorker_Success(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "text/html")
		_, _ = w.Write([]byte(testHTML))
	}))
	defer srv.Close()

	items := &mockItemService{}
	w := &PageFetchWorker{
		Items:  items,
		Client: srv.Client(),
	}

	job := &river.Job[PageFetchArgs]{
		Args: PageFetchArgs{
			ItemID: uuid.New(),
			URL:    srv.URL,
		},
	}

	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("Work() returned error: %v", err)
	}

	// Should have called UpdateContent twice: processing + ready
	if len(items.updates) != 2 {
		t.Fatalf("expected 2 UpdateContent calls, got %d", len(items.updates))
	}

	if items.updates[0].Status != "processing" {
		t.Errorf("first update status = %q, want %q", items.updates[0].Status, "processing")
	}

	final := items.updates[1]
	if final.Status != "ready" {
		t.Errorf("final status = %q, want %q", final.Status, "ready")
	}
	if final.Title == nil || *final.Title == "" {
		t.Error("expected non-empty title in final update")
	}
	if final.ContentText == nil || *final.ContentText == "" {
		t.Error("expected non-empty content_text in final update")
	}
}

