		t.Fatalf("expected at least 2 updates, got %d", len(items.updates))
	}
	if items.updates[0].Status != "processing" {
		t.Errorf("first status = %q, want %q", items.updates[0].Status, "processing")
	}
	if items.updates[1].Status != "error" {
		t.Errorf("second status = %q, want %q", items.updates[1].Status, "error")
	}
}

func TestPageFetchArgs_JSONRoundTrip(t *testing.T) {
	itemID := uuid.New()
	args := PageFetchArgs{
		ItemID: itemID,
		URL:    "https://example.com/article",
	}

	data, err := json.Marshal(args)
	if err != nil {
		t.Fatalf("Marshal: %v", err)
	}

	var decoded PageFetchArgs
	if err := json.Unmarshal(data, &decoded); err != nil {
		t.Fatalf("Unmarshal: %v", err)
	}

	if decoded.ItemID != itemID {
		t.Errorf("ItemID = %v, want %v", decoded.ItemID, itemID)
	}
	if decoded.URL != "https://example.com/article" {
		t.Errorf("URL = %q, want %q", decoded.URL, "https://example.com/article")
	}
}

